import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"无双龙","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/无双龙.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/无双龙.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/3.C级/无双龙.md"};function o(d,b,l,_,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"无双龙",tabindex:"-1"},[t("无双龙 "),r("a",{class:"header-anchor",href:"#无双龙","aria-label":'Permalink to "无双龙"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风024")])])],-1),n('<h1 id="无双龙-1" tabindex="-1">无双龙 <a class="header-anchor" href="#无双龙-1" aria-label="Permalink to &quot;无双龙&quot;">​</a></h1><p>无双龙（龙深红者）<br> C级随从<br> C+2000<br> 该随从可自由行动<br> 红龙型的怪物。基本颜色为红色。剧中被莲以“巨物”评论，在怪物之中也算是强有力一类。空中飞行，以剑状的尾巴“龙之巨尾”与口中吐出的5000℃的火球“龙之吐息”为武器。<br> 最初将真司视为食物，在与之契约后给予了其龙骑之力。有着契约后仅仅因为看见了真司放弃战斗的态度就打算将其食杀等非常凶暴的性格。但伴随着契约的长期化，慢慢地对真司寄予了信赖，在来不及使用“降临（龙骑）”的卡片或是走投无路的时候，会主动出现。<br> 名称的由来是，意味着龙的“dragon”与意味着红色的“red”再添加“er”的后缀。</p><p>随从体积：17</p><p>随从属性：<br> 生理属性<br> 力量：11<br> 敏捷：9<br> 耐力：11<br> 心智属性<br> 智力：6<br> 感知：6<br> 决心：9<br> 互动属性<br> 风度：6<br> 操控：9<br> 沉着：6</p><p>随从技能：<br> 生理系<br> 运动8<br> 专业：反射5<br> 求生5<br> 专业：强韧5<br> 射击1<br> 专业：<br> 武技8<br> 专业：爪击8 吐息8</p><p>心智系<br> 学识5<br> 专业：身体掌握5<br> 器用1<br> 专业：<br> 手艺1<br> 专业：<br> 专注5<br> 专业：意志5</p><p>互动系<br> 洞察5<br> 专业：侦查5<br> 隐秘1<br> 专业：<br> 表达1<br> 专业：<br> 社交1<br> 专业</p><p>衍生属性值<br> 体积<br> 速度 （力量【11】+敏捷【9】+体积【17】+每1点敏捷上的附加获得3移动速度）=40<br> 先攻 （敏捷【9】+沉着【6】）= 15<br> 防御 （敏捷感知的平均值【7】+较高者的附加成功【1】）=7+1<br> 生命值 （耐力【11】+体积【5】+耐力附加【2】×5）=26<br> 意志力池 （决心【9】+沉着【6】+决心附加【1】×2）=16<br> 意志 （决心【9】+专注+意志【10+2】）= 19+3<br> 反射 （敏捷【9】+运动+反射【13+2】）= 22+3<br> 强韧 （耐力【11】+生存+强韧【10+2】）= 21+4<br> 侦查 （感知【6】+洞察+侦查【10+2】）= 16+3<br> 敏感范围 （感知【6】*20米+感知上的附加成功【1】*20米）=140米</p><p>攻击预设：<br> 近身爪击：11+8+8+5+3=35+5 射程：触及<br> 火焰吐息：11+8+8+5+3=35+5 射程：40米，目标：射程内单体敌人</p><p>特殊效果：攻击会附带一点不可豁免的燃烧点数</p><p>防御预设：<br> 基础防御：7+1</p><p>专长：<br> 巨型生物：无双龙无论在镜怪兽还是现实之中都是极其巨大的一种生物，在基础体积5的基础上提供12点体积，但是不提供生命上限，而近战伤害也因此获得了提升至3L</p><p>烈火之龙：作为一只龙，无双龙也会使用吐息来进行攻击，可以使用力量+武技+吐息+身体掌握来进行攻击检定，并且该攻击的伤害类型为火焰伤害，攻击射程为40米并且基础伤害被提升至3L。并且因为对于烈焰的掌控强大无比，所以不论是近战还是远程攻击，无双龙身上的火属性的能量都可以使得敌人燃烧，无双龙的攻击在命中后会使敌人受到1点不可豁免的燃烧点数。</p><p>飞空生物：无双龙作为一只龙自然有着在天空之中自由飞行的能力，具有【完美飞行】</p><p>镜怪兽空间：因为镜怪兽天生便在镜世界之中生存，所以自然而然的学会了如何控制自己身体之上的反光面开辟一份独属于自己的10立方米空间的能力，其中不能装独立单位，使用者放入/取出物品至少是一个迅捷动作。</p><p>契约兽（无双龙）下属武器：<br> 模仿契约兽无双龙身上的特性然后靠着契约卡系统的能力制作而成的武器与护盾，其中蕴含着契约兽身体之中的特殊能力，但是因为龙骑召唤机的特殊性所以其中的龙军刀已经与召唤机绑定，无法单独售卖。在其下购买的武器和护盾在购买后都储存在无双龙的体内，需要一个迅捷动作命令契约兽释放来取出和使用，画风为契约兽释放从天上飞下来你的武器和护盾自动装备在你的身上。</p><p>龙利爪<br> C+1000<br> C级武器<br> 龙骑所使用的模仿了“龙深红者”的头部的手甲。2000AP。装备于右腕上使用。本来设定是可以作为打击武器，但如此使用的案例较少。也存在着将“龙军刀”的柄被嵌入龙首的下颚部分中的剧照，但在剧中未使用。（因为没造型我也就没写）<br> 类型：拳套<br> 基础属性：4附加<br> 体积：1<br> 【烈焰之力】：无双龙的火焰之力缠绕在其上，使得其之上无时无刻都燃烧着那无形的烈火，其中的烈火打在敌人的身上都会熊熊燃烧，使其陷入那烈火汹涌之中，你的每次攻击都将附带1点不可豁免的燃烧点数。<br> 【兼容武器】：龙利爪只有右手部件，目的就是让使用者可以更好的搭配着其他武器来使用，也可以兼容两把武器使得伤害得到更大的提升，当你双手各持有一把武器时，你可以将未加入攻击的另一把武器的基础属性一半与所有特性加入攻击中</p><p>龙护盾<br> C+1000<br> C级护盾<br> 龙骑所使用的模仿了“龙深红者”的腹部的盾牌。2000GP。可以同时召唤两面。除了手持使用外，也可装备于两肩与其它武器并用。<br> 类型：轻盾<br> 基础属性：2L 格挡11<br> 体积：3<br> 【龙之盾】：龙护盾在装备时会增强使用者的防御，在你装备该武器时身上也被无双龙身上防护敌人的钢铁之意所笼罩，你获得6点器械防御和基于器械防御的1点全吸收</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',20)])])}const C=e(s,[["render",o]]);export{f as __pageData,C as default};
